<?php namespace App\Domains\BeautyShop\Policies; use Illuminate\Auth\Access\HandlesAuthorization; class BeautyProductPolicy { use HandlesAuthorization; public function viewAny($user) { return true; } public function view($user, $product) { return $user->tenant_id === $product->tenant_id; } public function create($user) { return true; } public function update($user, $product) { return $user->tenant_id === $product->tenant_id; } public function delete($user, $product) { return $user->tenant_id === $product->tenant_id; } }
